import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Link, useNavigate, useSearchParams } from "react-router-dom";
import logoFallback from "@/assets/xiaoxiong-logo-christmas.png";
import { useSiteSettings } from "@/hooks/useSiteSettings";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { InputOTP, InputOTPGroup, InputOTPSlot } from "@/components/ui/input-otp";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Eye, EyeOff, ArrowLeft } from "lucide-react";

const Auth = () => {
  const { signIn, signUp, signInWithGoogle, signInWithApple, signInWithPhone, verifyOTP, user, isBanned, isCheckingBanStatus } = useAuth();
  const { settings } = useSiteSettings();
  const logoUrl = settings?.logo_url || logoFallback;
  const logoWidth = settings?.logo_width || 35;
  const logoHeight = settings?.logo_height || 35;
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const [isLoading, setIsLoading] = useState(false);
  const [activeTab, setActiveTab] = useState(() => {
    const mode = searchParams.get("mode");
    return mode === "register" ? "register" : "login";
  });
  const [phoneStep, setPhoneStep] = useState<"phone" | "otp">("phone");
  const [phoneNumber, setPhoneNumber] = useState("");
  const [countryCode, setCountryCode] = useState("+351");
  const [registerStep, setRegisterStep] = useState<"info" | "verify">("info");
  const [registerEmail, setRegisterEmail] = useState("");
  const [registerData, setRegisterData] = useState<RegisterFormData | null>(null);
  const [resendCountdown, setResendCountdown] = useState(0);
  const [passwordStrength, setPasswordStrength] = useState<'weak' | 'medium' | 'strong' | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [showRegisterPassword, setShowRegisterPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(() => {
    // 默认勾选「保持登录」：仅当用户曾显式取消时才为 false
    try {
      const v = localStorage.getItem("rememberMe");
      return v === null ? true : v === "true";
    } catch (e) {
      return true;
    }
  });
  
  // Forgot password states
  const [showForgotPassword, setShowForgotPassword] = useState(false);
  const [forgotPasswordStep, setForgotPasswordStep] = useState<"email" | "verify" | "newPassword">("email");
  const [forgotPasswordEmail, setForgotPasswordEmail] = useState("");
  const [forgotPasswordCode, setForgotPasswordCode] = useState("");
  const [showNewPassword, setShowNewPassword] = useState(false);
  const [showConfirmNewPassword, setShowConfirmNewPassword] = useState(false);
  const [newPasswordStrength, setNewPasswordStrength] = useState<'weak' | 'medium' | 'strong' | null>(null);
  
  // Login security states
  const [isLoginLocked, setIsLoginLocked] = useState(false);
  const [lockoutSeconds, setLockoutSeconds] = useState(0);
  const [remainingAttempts, setRemainingAttempts] = useState<number | null>(null);
  
  const { t } = useTranslation();

  const loginSchema = z.object({
    email: z.string().email(t("auth.invalidEmail")),
    password: z.string().min(6, t("auth.passwordMin")),
  });

  const registerSchema = z.object({
    displayName: z.string().min(2, t("auth.displayNameMin")),
    email: z.string().email(t("auth.invalidEmail")),
    password: z.string().min(6, t("auth.passwordMin")),
    confirmPassword: z.string(),
  }).refine((data) => data.password === data.confirmPassword, {
    message: t("auth.passwordsDontMatch"),
    path: ["confirmPassword"],
  });

  const phoneSchema = z.object({
    phone: z.string().min(6, t("auth.phoneMin")),
  });

  const otpSchema = z.object({
    otp: z.string().length(6, t("auth.otpLength")),
  });

  const emailVerifySchema = z.object({
    code: z.string().length(4, "Verification code must be 4 digits"),
  });

  const forgotPasswordEmailSchema = z.object({
    email: z.string().email(t("auth.invalidEmail")),
  });

  const forgotPasswordVerifySchema = z.object({
    code: z.string().length(4, "Verification code must be 4 digits"),
  });

  const forgotPasswordNewSchema = z.object({
    newPassword: z.string().min(6, t("auth.passwordMin")),
    confirmNewPassword: z.string(),
  }).refine((data) => data.newPassword === data.confirmNewPassword, {
    message: t("auth.passwordsDontMatch"),
    path: ["confirmNewPassword"],
  });

  type LoginFormData = z.infer<typeof loginSchema>;
  type RegisterFormData = z.infer<typeof registerSchema>;
  type PhoneFormData = z.infer<typeof phoneSchema>;
  type OTPFormData = z.infer<typeof otpSchema>;
  type EmailVerifyFormData = z.infer<typeof emailVerifySchema>;
  type ForgotPasswordEmailFormData = z.infer<typeof forgotPasswordEmailSchema>;
  type ForgotPasswordVerifyFormData = z.infer<typeof forgotPasswordVerifySchema>;
  type ForgotPasswordNewFormData = z.infer<typeof forgotPasswordNewSchema>;

  const loginForm = useForm<LoginFormData>({
    resolver: zodResolver(loginSchema),
  });

  const registerForm = useForm<RegisterFormData>({
    resolver: zodResolver(registerSchema),
  });

  const phoneForm = useForm<PhoneFormData>({
    resolver: zodResolver(phoneSchema),
  });

  const otpForm = useForm<OTPFormData>({
    resolver: zodResolver(otpSchema),
  });

  const emailVerifyForm = useForm<EmailVerifyFormData>({
    resolver: zodResolver(emailVerifySchema),
  });

  const forgotPasswordEmailForm = useForm<ForgotPasswordEmailFormData>({
    resolver: zodResolver(forgotPasswordEmailSchema),
  });

  const forgotPasswordVerifyForm = useForm<ForgotPasswordVerifyFormData>({
    resolver: zodResolver(forgotPasswordVerifySchema),
  });

  const forgotPasswordNewForm = useForm<ForgotPasswordNewFormData>({
    resolver: zodResolver(forgotPasswordNewSchema),
  });

  // Clear stale auth cache on mount - if user is on login page, any local auth tokens are useless
  useEffect(() => {
    if (!user) {
      try {
        const keysToRemove: string[] = [];
        for (let i = 0; i < localStorage.length; i++) {
          const key = localStorage.key(i);
          if (key && (key.startsWith("sb-") && (key.endsWith("-auth-token") || key.endsWith("-auth-token-code-verifier")))) {
            keysToRemove.push(key);
          }
        }
        keysToRemove.forEach(key => localStorage.removeItem(key));
        if (keysToRemove.length > 0) {
          console.info(`[Auth] Cleared ${keysToRemove.length} stale auth cache entries`);
        }
      } catch (e) {
        // localStorage may be restricted
      }
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // SSO: capture redirect_uri & provider from URL params on mount
  // Note: auto-trigger lives in a separate effect below so handleGoogle/AppleSignIn are defined.
  useEffect(() => {
    const ssoRedirect = searchParams.get("sso_redirect");

    const ALLOWED_HOSTS = [
      "ai-site-builder-xiaoxiong.lovable.app",
      "site.xiaoxiong.pt",
    ];

    if (ssoRedirect) {
      try {
        const url = new URL(ssoRedirect);
        if (!ALLOWED_HOSTS.includes(url.hostname)) {
          toast.error(t("auth.ssoInvalidRedirect"));
          return;
        }
        sessionStorage.setItem("sso_redirect", ssoRedirect);
      } catch {
        toast.error(t("auth.ssoInvalidRedirect"));
        return;
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    // Don't navigate if user is banned or ban check is in progress
    if (user && !isBanned && !isCheckingBanStatus) {
      // Check pending SSO redirect
      const ssoRedirect = sessionStorage.getItem("sso_redirect");
      if (ssoRedirect) {
        sessionStorage.removeItem("sso_redirect");
        (async () => {
          try {
            const { data, error } = await supabase.functions.invoke("generate-sso-token", {
              body: { redirect_uri: ssoRedirect },
            });
            if (error || !data?.token) {
              console.error("SSO token error:", error, data);
              toast.error(t("auth.ssoTokenFailed"));
              await new Promise((r) => setTimeout(r, 600));
              navigate("/");
              return;
            }
            const sep = ssoRedirect.includes("?") ? "&" : "?";
            window.location.href = `${ssoRedirect}${sep}token=${encodeURIComponent(data.token)}`;
          } catch (e) {
            console.error("SSO token generation failed:", e);
            toast.error(t("auth.ssoTokenFailed"));
            await new Promise((r) => setTimeout(r, 600));
            navigate("/");
          }
        })();
        return;
      }
      navigate("/");
    }
  }, [user, navigate, isBanned, isCheckingBanStatus, t]);

  useEffect(() => {
    let timer: NodeJS.Timeout;
    if (resendCountdown > 0) {
      timer = setTimeout(() => setResendCountdown(resendCountdown - 1), 1000);
    }
    return () => clearTimeout(timer);
  }, [resendCountdown]);

  // Lockout countdown timer
  useEffect(() => {
    let timer: NodeJS.Timeout;
    if (lockoutSeconds > 0) {
      timer = setTimeout(() => setLockoutSeconds(lockoutSeconds - 1), 1000);
      if (lockoutSeconds <= 1) {
        setIsLoginLocked(false);
        setRemainingAttempts(null);
      }
    }
    return () => clearTimeout(timer);
  }, [lockoutSeconds]);

  // Check login security on component mount
  useEffect(() => {
    const checkInitialSecurity = async () => {
      try {
        const { data, error } = await supabase.functions.invoke("check-login-security", {
          body: { action: "check" },
        });
        if (!error && data?.isLimited) {
          setIsLoginLocked(true);
          setLockoutSeconds(data.remainingSeconds);
        }
      } catch (e) {
        console.error("Failed to check login security:", e);
      }
    };
    checkInitialSecurity();
  }, []);

  const checkPasswordStrength = (password: string): 'weak' | 'medium' | 'strong' => {
    let strength = 0;
    
    if (password.length >= 6) strength++;
    if (password.length >= 8) strength++;
    if (/[a-z]/.test(password)) strength++;
    if (/[A-Z]/.test(password)) strength++;
    if (/[0-9]/.test(password)) strength++;
    if (/[^a-zA-Z0-9]/.test(password)) strength++;
    
    if (strength <= 2) return 'weak';
    if (strength <= 4) return 'medium';
    return 'strong';
  };

  const handleLogin = async (data: LoginFormData) => {
    // Check if currently locked out
    if (isLoginLocked) {
      const minutes = Math.ceil(lockoutSeconds / 60);
      toast.error(t("auth.tooManyAttempts", { minutes }));
      return;
    }

    setIsLoading(true);
    try {
      // Clear stale auth cache before login to prevent 429 storms
      try {
        for (let i = localStorage.length - 1; i >= 0; i--) {
          const key = localStorage.key(i);
          if (key && key.startsWith("sb-") && (key.endsWith("-auth-token") || key.endsWith("-auth-token-code-verifier"))) {
            localStorage.removeItem(key);
          }
        }
      } catch (e) { /* localStorage restricted */ }

      // First check rate limit
      const { data: securityCheck, error: securityError } = await supabase.functions.invoke("check-login-security", {
        body: { action: "check" },
      });

      if (!securityError && securityCheck?.isLimited) {
        setIsLoginLocked(true);
        setLockoutSeconds(securityCheck.remainingSeconds);
        const minutes = Math.ceil(securityCheck.remainingSeconds / 60);
        toast.error(t("auth.tooManyAttempts", { minutes }));
        setIsLoading(false);
        return;
      }

      const { error } = await signIn(data.email, data.password, rememberMe);
      
      if (error) {
        // 认证服务限流（不是账号密码错误）
        const message = String(error?.message || "").toLowerCase();
        const code = String((error as any)?.code || "").toLowerCase();
        const isAuthRateLimited =
          code === "over_request_rate_limit" ||
          message.includes("rate limit") ||
          message.includes("over_request_rate_limit");

        // Check if user is banned - dialog is shown by AuthContext, just return
        if (error.message === "ACCOUNT_BANNED") {
          return;
        }

        if (isAuthRateLimited) {
          toast.error(t("toast.authRateLimited"));
          return;
        }
        
        // Record failed attempt - always show generic error (security best practice)
        await supabase.functions.invoke("check-login-security", {
          body: { action: "record", email: data.email, success: false },
        }).then(({ data: recordResult }) => {
          if (recordResult?.isLimited) {
            setIsLoginLocked(true);
            setLockoutSeconds(recordResult.remainingSeconds);
            const minutes = Math.ceil(recordResult.remainingSeconds / 60);
            toast.error(t("auth.tooManyAttempts", { minutes }));
          } else if (recordResult?.attemptCount !== undefined) {
            const remaining = 5 - recordResult.attemptCount;
            setRemainingAttempts(remaining > 0 ? remaining : 0);
            // Always show generic error message for security (prevents account enumeration)
            toast.error(t("auth.invalidCredentials"));
            if (remaining > 0 && remaining <= 3) {
              toast.warning(t("auth.remainingAttempts", { count: remaining }));
            }
          }
        });
        return;
      }
      
      // Record successful login
      await supabase.functions.invoke("check-login-security", {
        body: { action: "record", email: data.email, success: true },
      });
      setRemainingAttempts(null);
      
      toast.success(t("auth.signInSuccess"));
      // Explicitly navigate after successful login to avoid race conditions
      // with onAuthStateChange re-triggering isCheckingBanStatus
      navigate("/");
    } catch (error: any) {
      // Always show generic error for security
      toast.error(t("auth.invalidCredentials"));
    } finally {
      setIsLoading(false);
    }
  };

  const handleRegister = async (data: RegisterFormData) => {
    setIsLoading(true);
    try {
      // First check if email is already registered
      const { data: checkResult, error: checkError } = await supabase.functions.invoke(
        "check-email-registered",
        {
          body: { email: data.email },
        }
      );

      if (checkError) {
        console.error("Check email error:", checkError);
        toast.error(t("error.general"));
        return;
      }

      // If email is already registered, prompt user to login or reset password
      if (checkResult?.registered) {
        toast.error(t("auth.emailAlreadyRegisteredUseLogin"));
        return;
      }

      // Store registration data and send verification code
      setRegisterData(data);
      setRegisterEmail(data.email);
      
      const { error } = await supabase.functions.invoke("send-verification-code", {
        body: { email: data.email },
      });
      
      if (error) {
        toast.error(t("auth.verificationCodeFailed"));
        console.error(error);
        return;
      }
      
      setRegisterStep("verify");
      toast.success(t("auth.verificationCodeSent"));
      setResendCountdown(30);
    } catch (error: any) {
      toast.error(error.message || t("error.general"));
    } finally {
      setIsLoading(false);
    }
  };

  const handleVerifyAndRegister = async (data: EmailVerifyFormData) => {
    if (!registerData) return;
    
    setIsLoading(true);
    try {
      // Verify the code first
      const { data: verifyResult, error: verifyError } = await supabase.functions.invoke(
        "verify-email-code",
        {
          body: { 
            email: registerEmail, 
            code: data.code 
          },
        }
      );
      
      if (verifyError || !verifyResult?.success) {
        toast.error(verifyResult?.error || t("auth.invalidVerificationCode"));
        return;
      }
      
      // If verification successful, proceed with registration
      const { data: signUpData, error: signUpError } = await signUp(
        registerData.email,
        registerData.password,
        registerData.displayName
      );
      
      if (signUpError) {
        if (signUpError.message.includes("already registered")) {
          toast.error(t("auth.emailAlreadyRegisteredUseLogin"));
        } else {
          toast.error(signUpError.message);
        }
        return;
      }
      
      // Check if identities is empty (indicates existing user - Supabase security feature)
      if (!signUpData?.user?.identities || signUpData.user.identities.length === 0) {
        toast.error(t("auth.emailAlreadyRegisteredUseLogin"));
        return;
      }
      
      toast.success(t("auth.signUpSuccess"));
      setActiveTab("login");
      setRegisterStep("info");
      registerForm.reset();
      emailVerifyForm.reset();
      setRegisterData(null);
    } catch (error: any) {
      toast.error(error.message || t("error.general"));
    } finally {
      setIsLoading(false);
    }
  };

  const handleResendCode = async () => {
    if (resendCountdown > 0) return;
    
    setIsLoading(true);
    try {
      const emailToResend = showForgotPassword ? forgotPasswordEmail : registerEmail;
      const { error } = await supabase.functions.invoke("send-verification-code", {
        body: { email: emailToResend },
      });
      
      if (error) {
        toast.error(t("toast.resendCodeFailed"));
        return;
      }
      
      toast.success(t("toast.verificationCodeResent"));
      setResendCountdown(30);
    } catch (error: any) {
      toast.error(error.message || "Failed to resend code");
    } finally {
      setIsLoading(false);
    }
  };

  const friendlyOAuthError = (err: any): string => {
    const msg = String(err?.message || "").toLowerCase();
    if (msg.includes("popup") || msg.includes("closed") || msg.includes("cancel")) {
      return t("auth.oauthCancelled");
    }
    if (msg.includes("network") || msg.includes("fetch") || msg.includes("timeout")) {
      return t("auth.oauthNetworkError");
    }
    if (msg.includes("not enabled") || msg.includes("provider")) {
      return t("auth.oauthProviderError");
    }
    return t("auth.oauthGenericError");
  };

  const handleGoogleSignIn = async () => {
    setIsLoading(true);
    try {
      // If SSO flow pending, force OAuth callback to /auth so the redirect handler runs
      const hasSso = !!sessionStorage.getItem("sso_redirect");
      const redirectTo = hasSso ? `${window.location.origin}/auth` : undefined;
      const { error } = await signInWithGoogle(redirectTo);
      if (error) {
        console.error("Google OAuth error:", error);
        toast.error(friendlyOAuthError(error));
        setIsLoading(false);
      }
      // On success the browser is redirecting away; keep isLoading=true to lock UI.
    } catch (error: any) {
      console.error("Google OAuth threw:", error);
      toast.error(friendlyOAuthError(error));
      setIsLoading(false);
    }
  };

  const handleAppleSignIn = async () => {
    setIsLoading(true);
    try {
      const hasSso = !!sessionStorage.getItem("sso_redirect");
      const redirectTo = hasSso ? `${window.location.origin}/auth` : undefined;
      const { error } = await signInWithApple(redirectTo);
      if (error) {
        console.error("Apple OAuth error:", error);
        toast.error(friendlyOAuthError(error));
        setIsLoading(false);
      }
      // On success the browser is redirecting away; keep isLoading=true to lock UI.
    } catch (error: any) {
      console.error("Apple OAuth threw:", error);
      toast.error(friendlyOAuthError(error));
      setIsLoading(false);
    }
  };

  // SSO auto-trigger: runs after handleGoogle/AppleSignIn are defined
  useEffect(() => {
    const provider = searchParams.get("provider");
    if (!user && (provider === "google" || provider === "apple")) {
      setIsLoading(true);
      if (provider === "google") {
        handleGoogleSignIn();
      } else {
        handleAppleSignIn();
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handlePhoneLogin = async (data: PhoneFormData) => {
    setIsLoading(true);
    try {
      const fullPhoneNumber = `${countryCode}${data.phone}`;
      const { error } = await signInWithPhone(fullPhoneNumber);

      if (error) {
        const msg = String(error?.message || "").toLowerCase();
        if (msg.includes("rate") || msg.includes("limit")) {
          toast.error(t("toast.authRateLimited"));
        } else if (msg.includes("invalid") && msg.includes("phone")) {
          toast.error(t("auth.invalidPhone"));
        } else {
          toast.error(t("auth.phoneSendFailed"));
        }
        return;
      }

      setPhoneNumber(fullPhoneNumber);
      setPhoneStep("otp");
      toast.success(t("auth.otpSent"));
    } catch (error: any) {
      toast.error(t("auth.phoneSendFailed"));
    } finally {
      setIsLoading(false);
    }
  };

  const handleOTPVerify = async (data: OTPFormData) => {
    setIsLoading(true);
    try {
      const { error } = await verifyOTP(phoneNumber, data.otp);

      if (error) {
        const msg = String(error?.message || "").toLowerCase();
        if (msg.includes("expired")) {
          toast.error(t("auth.otpExpired"));
        } else if (msg.includes("invalid") || msg.includes("token")) {
          toast.error(t("auth.invalidOtp"));
        } else {
          toast.error(t("auth.otpVerifyFailed"));
        }
        return;
      }

      toast.success(t("auth.signInSuccess"));
      // Navigation is handled by the user useEffect after session is set
    } catch (error: any) {
      toast.error(t("auth.otpVerifyFailed"));
    } finally {
      setIsLoading(false);
    }
  };

  // Forgot password handlers
  const handleForgotPasswordEmailSubmit = async (data: ForgotPasswordEmailFormData) => {
    setIsLoading(true);
    try {
      // Check if email is registered
      const { data: checkResult, error: checkError } = await supabase.functions.invoke(
        "check-email-registered",
        {
          body: { email: data.email },
        }
      );

      if (checkError) {
        toast.error(t("error.general"));
        return;
      }

      if (!checkResult?.registered) {
        toast.error(t("auth.emailNotRegistered"));
        return;
      }

      // Send verification code
      const { data: sendResult, error } = await supabase.functions.invoke("send-verification-code", {
        body: { email: data.email },
      });

      if (error || !sendResult?.success) {
        const detail = sendResult?.error || error?.message;
        toast.error(detail ? `${t("auth.verificationCodeFailed")}: ${detail}` : t("auth.verificationCodeFailed"));
        return;
      }

      setForgotPasswordEmail(data.email);
      setForgotPasswordStep("verify");
      toast.success(t("auth.verificationCodeSent"));
      setResendCountdown(30);
    } catch (error: any) {
      toast.error(error.message || t("error.general"));
    } finally {
      setIsLoading(false);
    }
  };

  const handleForgotPasswordVerify = async (data: ForgotPasswordVerifyFormData) => {
    setIsLoading(true);
    try {
      const { data: verifyResult, error: verifyError } = await supabase.functions.invoke(
        "verify-email-code",
        {
          body: { 
            email: forgotPasswordEmail, 
            code: data.code 
          },
        }
      );
      
      if (verifyError || !verifyResult?.success) {
        toast.error(verifyResult?.error || t("auth.invalidVerificationCode"));
        return;
      }
      
      // Store the verified code for the next step
      setForgotPasswordCode(data.code);
      setForgotPasswordStep("newPassword");
      toast.success(t("auth.codeVerified"));
    } catch (error: any) {
      toast.error(error.message || t("error.general"));
    } finally {
      setIsLoading(false);
    }
  };

  const handleResetPassword = async (data: ForgotPasswordNewFormData) => {
    setIsLoading(true);
    try {
      // Call reset-password function with the stored verified code
      const { data: resetResult, error: resetError } = await supabase.functions.invoke(
        "reset-password",
        {
          body: { 
            email: forgotPasswordEmail, 
            code: forgotPasswordCode,
            newPassword: data.newPassword
          },
        }
      );
      
      if (resetError || !resetResult?.success) {
        toast.error(resetResult?.error || t("auth.passwordResetFailed"));
        return;
      }
      
      toast.success(t("auth.passwordResetSuccess"));
      handleBackToLogin();
    } catch (error: any) {
      toast.error(error.message || t("error.general"));
    } finally {
      setIsLoading(false);
    }
  };

  const handleBackToLogin = () => {
    setShowForgotPassword(false);
    setForgotPasswordStep("email");
    setForgotPasswordEmail("");
    setForgotPasswordCode("");
    forgotPasswordEmailForm.reset();
    forgotPasswordVerifyForm.reset();
    forgotPasswordNewForm.reset();
    setNewPasswordStrength(null);
  };

  // Forgot password UI
  if (showForgotPassword) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-hero p-4">
        <Card className="w-full max-w-md shadow-large">
          <CardHeader className="text-center">
            <div className="flex justify-center mb-4">
              <img 
                src={logoUrl} 
                alt="Logo" 
                style={{ width: `${logoWidth}px`, height: `${logoHeight}px` }}
                className="object-contain drop-shadow-md"
              />
            </div>
            <CardTitle className="text-2xl">{t("auth.forgotPassword")}</CardTitle>
            <CardDescription>
              {forgotPasswordStep === "email" && t("auth.forgotPasswordDescription")}
              {forgotPasswordStep === "verify" && t("auth.verifyCodeDescription")}
              {forgotPasswordStep === "newPassword" && t("auth.setNewPasswordDescription")}
            </CardDescription>
          </CardHeader>

          <CardContent>
            {forgotPasswordStep === "email" && (
              <form onSubmit={forgotPasswordEmailForm.handleSubmit(handleForgotPasswordEmailSubmit)} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="forgot-email">{t("auth.email")}</Label>
                  <Input
                    id="forgot-email"
                    type="email"
                    placeholder="you@example.com"
                    {...forgotPasswordEmailForm.register("email")}
                  />
                  {forgotPasswordEmailForm.formState.errors.email && (
                    <p className="text-sm text-destructive">{forgotPasswordEmailForm.formState.errors.email.message}</p>
                  )}
                </div>
                <Button type="submit" className="w-full" disabled={isLoading}>
                  {isLoading ? t("auth.sendingCode") : t("auth.sendCode")}
                </Button>
              </form>
            )}

            {forgotPasswordStep === "verify" && (
              <form onSubmit={forgotPasswordVerifyForm.handleSubmit(handleForgotPasswordVerify)} className="space-y-4">
                <div className="space-y-2">
                  <Label>{t("auth.verificationCode")}</Label>
                  <p className="text-xs text-muted-foreground mb-2">
                    {t("auth.verificationCodeHint", { email: forgotPasswordEmail })}
                  </p>
                  <div className="flex justify-center">
                    <InputOTP
                      maxLength={4}
                      {...forgotPasswordVerifyForm.register("code")}
                      onChange={(value) => forgotPasswordVerifyForm.setValue("code", value)}
                    >
                      <InputOTPGroup>
                        <InputOTPSlot index={0} />
                        <InputOTPSlot index={1} />
                        <InputOTPSlot index={2} />
                        <InputOTPSlot index={3} />
                      </InputOTPGroup>
                    </InputOTP>
                  </div>
                  {forgotPasswordVerifyForm.formState.errors.code && (
                    <p className="text-sm text-destructive text-center">{forgotPasswordVerifyForm.formState.errors.code.message}</p>
                  )}
                </div>
                <div className="flex gap-2">
                  <Button 
                    type="button" 
                    variant="outline" 
                    className="w-full"
                    onClick={() => setForgotPasswordStep("email")}
                  >
                    {t("common.back")}
                  </Button>
                  <Button type="submit" className="w-full" disabled={isLoading}>
                    {isLoading ? t("auth.verifying") : t("auth.verify")}
                  </Button>
                </div>
                <Button 
                  type="button" 
                  variant="ghost" 
                  className="w-full text-sm"
                  onClick={handleResendCode}
                  disabled={isLoading || resendCountdown > 0}
                >
                  {resendCountdown > 0 
                    ? t("auth.resendIn", { seconds: resendCountdown })
                    : t("auth.resendCode")}
                </Button>
              </form>
            )}

            {forgotPasswordStep === "newPassword" && (
              <form onSubmit={forgotPasswordNewForm.handleSubmit(handleResetPassword)} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="new-password">{t("auth.newPassword")}</Label>
                  <div className="relative">
                    <Input
                      id="new-password"
                      type={showNewPassword ? "text" : "password"}
                      placeholder={t("auth.passwordPlaceholder")}
                      {...forgotPasswordNewForm.register("newPassword")}
                      onChange={(e) => {
                        forgotPasswordNewForm.setValue("newPassword", e.target.value);
                        if (e.target.value) {
                          setNewPasswordStrength(checkPasswordStrength(e.target.value));
                        } else {
                          setNewPasswordStrength(null);
                        }
                      }}
                    />
                    <button
                      type="button"
                      onClick={() => setShowNewPassword(!showNewPassword)}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                    >
                      {showNewPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                    </button>
                  </div>
                  {forgotPasswordNewForm.formState.errors.newPassword && (
                    <p className="text-sm text-destructive">{forgotPasswordNewForm.formState.errors.newPassword.message}</p>
                  )}
                  {newPasswordStrength && (
                    <div className="space-y-1">
                      <div className="flex gap-1">
                        <div className={`h-1.5 flex-1 rounded-full transition-colors ${
                          newPasswordStrength === 'weak' ? 'bg-destructive' : 
                          newPasswordStrength === 'medium' ? 'bg-warning' : 
                          'bg-success'
                        }`} />
                        <div className={`h-1.5 flex-1 rounded-full transition-colors ${
                          newPasswordStrength === 'medium' || newPasswordStrength === 'strong' ? 
                          newPasswordStrength === 'medium' ? 'bg-warning' : 'bg-success' : 
                          'bg-muted'
                        }`} />
                        <div className={`h-1.5 flex-1 rounded-full transition-colors ${
                          newPasswordStrength === 'strong' ? 'bg-success' : 'bg-muted'
                        }`} />
                      </div>
                      <p className={`text-xs ${
                        newPasswordStrength === 'weak' ? 'text-destructive' : 
                        newPasswordStrength === 'medium' ? 'text-warning' : 
                        'text-success'
                      }`}>
                        {t(`auth.passwordStrength.${newPasswordStrength}`)}
                      </p>
                    </div>
                  )}
                </div>
                <div className="space-y-2">
                  <Label htmlFor="confirm-new-password">{t("auth.confirmNewPassword")}</Label>
                  <div className="relative">
                    <Input
                      id="confirm-new-password"
                      type={showConfirmNewPassword ? "text" : "password"}
                      placeholder={t("auth.passwordPlaceholder")}
                      {...forgotPasswordNewForm.register("confirmNewPassword")}
                    />
                    <button
                      type="button"
                      onClick={() => setShowConfirmNewPassword(!showConfirmNewPassword)}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                    >
                      {showConfirmNewPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                    </button>
                  </div>
                  {forgotPasswordNewForm.formState.errors.confirmNewPassword && (
                    <p className="text-sm text-destructive">{forgotPasswordNewForm.formState.errors.confirmNewPassword.message}</p>
                  )}
                </div>
                <Button type="submit" className="w-full" disabled={isLoading}>
                  {isLoading ? t("common.loading") : t("auth.resetPassword")}
                </Button>
              </form>
            )}
          </CardContent>

          <CardFooter>
            <Button 
              variant="ghost" 
              className="w-full"
              onClick={handleBackToLogin}
            >
              <ArrowLeft className="h-4 w-4 mr-2" />
              {t("auth.backToLogin")}
            </Button>
          </CardFooter>
        </Card>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-hero p-4">
      <Card className="w-full max-w-md shadow-large">
        <CardHeader className="text-center">
          <div className="flex justify-center mb-4">
            <img 
              src={logoUrl} 
              alt="Logo" 
              style={{ width: `${logoWidth}px`, height: `${logoHeight}px` }}
              className="object-contain drop-shadow-md"
            />
          </div>
          <CardTitle className="text-2xl">{t("auth.welcome")}</CardTitle>
          <CardDescription>{t("auth.subtitle")}</CardDescription>
        </CardHeader>

        <CardContent>
          <Tabs value={activeTab} onValueChange={(value) => {
            setActiveTab(value);
            setPhoneStep("phone");
            setRegisterStep("info");
          }} className="w-full">
            <TabsList className="grid w-full grid-cols-2">
              <TabsTrigger value="login">{t("auth.login")}</TabsTrigger>
              {/* <TabsTrigger value="phone">{t("auth.phone")}</TabsTrigger> */}
              <TabsTrigger value="register">{t("auth.register")}</TabsTrigger>
            </TabsList>

            <TabsContent value="login">
              <form onSubmit={loginForm.handleSubmit(handleLogin)} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="email">{t("auth.email")}</Label>
                  <Input
                    id="email"
                    type="email"
                    placeholder="you@example.com"
                    {...loginForm.register("email")}
                  />
                  {loginForm.formState.errors.email && (
                    <p className="text-sm text-destructive">{loginForm.formState.errors.email.message}</p>
                  )}
                </div>
                <div className="space-y-2">
                  <Label htmlFor="password">{t("auth.password")}</Label>
                  <div className="relative">
                    <Input
                      id="password"
                      type={showPassword ? "text" : "password"}
                      placeholder="••••••••"
                      {...loginForm.register("password")}
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                    >
                      {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                    </button>
                  </div>
                  {loginForm.formState.errors.password && (
                    <p className="text-sm text-destructive">{loginForm.formState.errors.password.message}</p>
                  )}
                </div>
                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-2">
                    <Checkbox
                      id="rememberMe"
                      checked={rememberMe}
                      onCheckedChange={(checked) => {
                        setRememberMe(checked === true);
                        localStorage.setItem("rememberMe", String(checked === true));
                      }}
                    />
                    <Label htmlFor="rememberMe" className="text-sm font-normal cursor-pointer">
                      {t("auth.rememberMe")}
                    </Label>
                  </div>
                  <button
                    type="button"
                    className="text-sm text-primary hover:underline"
                    onClick={() => setShowForgotPassword(true)}
                  >
                    {t("auth.forgotPassword")}
                  </button>
                </div>
                
                {/* Lockout warning */}
                {isLoginLocked && (
                  <div className="p-3 bg-destructive/10 border border-destructive/20 rounded-md">
                    <p className="text-sm text-destructive font-medium">
                      {t("auth.accountLocked")}
                    </p>
                    <p className="text-xs text-destructive/80 mt-1">
                      {t("auth.tooManyAttempts", { minutes: Math.ceil(lockoutSeconds / 60) })}
                    </p>
                  </div>
                )}
                
                {/* Remaining attempts warning */}
                {!isLoginLocked && remainingAttempts !== null && remainingAttempts <= 3 && remainingAttempts > 0 && (
                  <div className="p-3 bg-yellow-500/10 border border-yellow-500/20 rounded-md">
                    <p className="text-sm text-yellow-600 dark:text-yellow-400">
                      {t("auth.remainingAttempts", { count: remainingAttempts })}
                    </p>
                  </div>
                )}
                
                <Button type="submit" className="w-full" disabled={isLoading || isLoginLocked}>
                  {isLoading ? t("auth.signingIn") : isLoginLocked ? `${t("auth.signIn")} (${Math.ceil(lockoutSeconds / 60)}m)` : t("auth.signIn")}
                </Button>
              
              </form>

              <div className="relative my-4">
                <div className="absolute inset-0 flex items-center">
                  <span className="w-full border-t" />
                </div>
                <div className="relative flex justify-center text-xs uppercase">
                  <span className="bg-card px-2 text-muted-foreground">{t("auth.orContinueWith")}</span>
                </div>
              </div>

              <Button 
                variant="outline" 
                className="w-full" 
                type="button"
                onClick={handleGoogleSignIn}
                disabled={isLoading}
              >
                <svg className="mr-2 h-4 w-4" viewBox="0 0 24 24">
                  <path
                    d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                    fill="#4285F4"
                  />
                  <path
                    d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                    fill="#34A853"
                  />
                  <path
                    d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                    fill="#FBBC05"
                  />
                  <path
                    d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                    fill="#EA4335"
                  />
                </svg>
                {t("auth.google")}
              </Button>

              <Button
                variant="outline"
                className="w-full mt-2"
                type="button"
                onClick={handleAppleSignIn}
                disabled={isLoading}
              >
                <svg className="mr-2 h-4 w-4" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
                  <path d="M16.365 1.43c0 1.14-.493 2.27-1.177 3.08-.744.9-1.99 1.57-2.987 1.57-.12 0-.23-.02-.3-.03-.01-.06-.04-.22-.04-.39 0-1.15.572-2.27 1.206-2.98.804-.94 2.142-1.64 3.248-1.68.03.13.05.28.05.43zm4.565 17.09c-.55 1.27-.81 1.84-1.52 2.96-.99 1.57-2.39 3.52-4.12 3.54-1.54.01-1.94-1-4.03-.99-2.09.01-2.53 1.01-4.07.99-1.73-.02-3.06-1.78-4.05-3.35-2.77-4.39-3.06-9.54-1.35-12.28C2.92 7.5 4.74 6.4 6.45 6.4c1.74 0 2.83.96 4.27.96 1.39 0 2.24-.96 4.25-.96 1.52 0 3.13.83 4.28 2.27-3.76 2.06-3.15 7.42-.32 8.85z" />
                </svg>
                {t("auth.apple")}
              </Button>
            </TabsContent>

            {/* Phone Login - Hidden
            <TabsContent value="phone">
              {phoneStep === "phone" ? (
                <form onSubmit={phoneForm.handleSubmit(handlePhoneLogin)} className="space-y-4">
                  <div className="space-y-2">
                    <Label htmlFor="phone-number">{t("auth.phoneNumber")}</Label>
                    <div className="flex gap-2">
                      <Select value={countryCode} onValueChange={setCountryCode}>
                        <SelectTrigger className="w-[120px]">
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="+351">🇵🇹 +351</SelectItem>
                          <SelectItem value="+86">🇨🇳 +86</SelectItem>
                          <SelectItem value="+1">🇺🇸 +1</SelectItem>
                          <SelectItem value="+44">🇬🇧 +44</SelectItem>
                          <SelectItem value="+33">🇫🇷 +33</SelectItem>
                          <SelectItem value="+49">🇩🇪 +49</SelectItem>
                          <SelectItem value="+81">🇯🇵 +81</SelectItem>
                          <SelectItem value="+82">🇰🇷 +82</SelectItem>
                          <SelectItem value="+55">🇧🇷 +55</SelectItem>
                          <SelectItem value="+34">🇪🇸 +34</SelectItem>
                        </SelectContent>
                      </Select>
                      <Input
                        id="phone-number"
                        type="tel"
                        placeholder="912 345 678"
                        className="flex-1"
                        {...phoneForm.register("phone")}
                      />
                    </div>
                    {phoneForm.formState.errors.phone && (
                      <p className="text-sm text-destructive">{phoneForm.formState.errors.phone.message}</p>
                    )}
                    <p className="text-xs text-muted-foreground">{t("auth.phoneHint")}</p>
                  </div>
                  <Button type="submit" className="w-full" disabled={isLoading}>
                    {isLoading ? t("auth.sendingCode") : t("auth.sendCode")}
                  </Button>
                </form>
              ) : (
                <form onSubmit={otpForm.handleSubmit(handleOTPVerify)} className="space-y-4">
                  <div className="space-y-2">
                    <Label htmlFor="otp">{t("auth.verificationCode")}</Label>
                    <div className="flex justify-center">
                      <InputOTP
                        maxLength={6}
                        {...otpForm.register("otp")}
                        onChange={(value) => otpForm.setValue("otp", value)}
                      >
                        <InputOTPGroup>
                          <InputOTPSlot index={0} />
                          <InputOTPSlot index={1} />
                          <InputOTPSlot index={2} />
                          <InputOTPSlot index={3} />
                          <InputOTPSlot index={4} />
                          <InputOTPSlot index={5} />
                        </InputOTPGroup>
                      </InputOTP>
                    </div>
                    {otpForm.formState.errors.otp && (
                      <p className="text-sm text-destructive text-center">{otpForm.formState.errors.otp.message}</p>
                    )}
                    <p className="text-xs text-muted-foreground text-center">{t("auth.otpHint", { phone: phoneNumber })}</p>
                  </div>
                  <div className="flex gap-2">
                    <Button 
                      type="button" 
                      variant="outline" 
                      className="w-full"
                      onClick={() => setPhoneStep("phone")}
                    >
                      {t("common.back")}
                    </Button>
                    <Button type="submit" className="w-full" disabled={isLoading}>
                      {isLoading ? t("auth.verifying") : t("auth.verify")}
                    </Button>
                  </div>
                </form>
              )}
            </TabsContent>
            */}

            <TabsContent value="register">
              {registerStep === "info" ? (
                <form onSubmit={registerForm.handleSubmit(handleRegister)} className="space-y-4">
                  <div className="space-y-2">
                    <Label htmlFor="display-name">{t("auth.displayName")}</Label>
                    <Input
                      id="display-name"
                      placeholder="John Doe"
                      {...registerForm.register("displayName")}
                    />
                    {registerForm.formState.errors.displayName && (
                      <p className="text-sm text-destructive">{registerForm.formState.errors.displayName.message}</p>
                    )}
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="register-email">{t("auth.email")}</Label>
                    <Input
                      id="register-email"
                      type="email"
                      placeholder="you@example.com"
                      {...registerForm.register("email")}
                    />
                    {registerForm.formState.errors.email && (
                      <p className="text-sm text-destructive">{registerForm.formState.errors.email.message}</p>
                    )}
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="register-password">{t("auth.password")}</Label>
                    <Input
                      id="register-password"
                      type="password"
                      placeholder={t("auth.passwordPlaceholder")}
                      {...registerForm.register("password")}
                      onChange={(e) => {
                        registerForm.setValue("password", e.target.value);
                        if (e.target.value) {
                          setPasswordStrength(checkPasswordStrength(e.target.value));
                        } else {
                          setPasswordStrength(null);
                        }
                      }}
                    />
                    {registerForm.formState.errors.password && (
                      <p className="text-sm text-destructive">{registerForm.formState.errors.password.message}</p>
                    )}
                    {passwordStrength && (
                      <div className="space-y-1">
                        <div className="flex gap-1">
                          <div className={`h-1.5 flex-1 rounded-full transition-colors ${
                            passwordStrength === 'weak' ? 'bg-destructive' : 
                            passwordStrength === 'medium' ? 'bg-warning' : 
                            'bg-success'
                          }`} />
                          <div className={`h-1.5 flex-1 rounded-full transition-colors ${
                            passwordStrength === 'medium' || passwordStrength === 'strong' ? 
                            passwordStrength === 'medium' ? 'bg-warning' : 'bg-success' : 
                            'bg-muted'
                          }`} />
                          <div className={`h-1.5 flex-1 rounded-full transition-colors ${
                            passwordStrength === 'strong' ? 'bg-success' : 'bg-muted'
                          }`} />
                        </div>
                        <p className={`text-xs ${
                          passwordStrength === 'weak' ? 'text-destructive' : 
                          passwordStrength === 'medium' ? 'text-warning' : 
                          'text-success'
                        }`}>
                          {t(`auth.passwordStrength.${passwordStrength}`)}
                        </p>
                      </div>
                    )}
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="confirm-password">{t("auth.confirmPassword")}</Label>
                    <Input
                      id="confirm-password"
                      type="password"
                      placeholder={t("auth.passwordPlaceholder")}
                      {...registerForm.register("confirmPassword")}
                    />
                    {registerForm.formState.errors.confirmPassword && (
                      <p className="text-sm text-destructive">{registerForm.formState.errors.confirmPassword.message}</p>
                    )}
                  </div>
                  <Button type="submit" className="w-full" disabled={isLoading}>
                    {isLoading ? t("auth.sendingCode") : t("auth.sendCode")}
                  </Button>
                </form>
              ) : (
                <form onSubmit={emailVerifyForm.handleSubmit(handleVerifyAndRegister)} className="space-y-4">
                  <div className="space-y-2">
                    <Label htmlFor="verification-code">Verification Code</Label>
                    <p className="text-xs text-muted-foreground mb-2">
                      Enter the 4-digit code sent to {registerEmail}
                    </p>
                    <div className="flex justify-center">
                      <InputOTP
                        maxLength={4}
                        {...emailVerifyForm.register("code")}
                        onChange={(value) => emailVerifyForm.setValue("code", value)}
                      >
                        <InputOTPGroup>
                          <InputOTPSlot index={0} />
                          <InputOTPSlot index={1} />
                          <InputOTPSlot index={2} />
                          <InputOTPSlot index={3} />
                        </InputOTPGroup>
                      </InputOTP>
                    </div>
                    {emailVerifyForm.formState.errors.code && (
                      <p className="text-sm text-destructive text-center">{emailVerifyForm.formState.errors.code.message}</p>
                    )}
                  </div>
                  <div className="flex gap-2">
                    <Button 
                      type="button" 
                      variant="outline" 
                      className="w-full"
                      onClick={() => {
                        setRegisterStep("info");
                        emailVerifyForm.reset();
                      }}
                    >
                      {t("common.back")}
                    </Button>
                    <Button type="submit" className="w-full" disabled={isLoading}>
                      {isLoading ? t("auth.verifying") : "Verify & Register"}
                    </Button>
                  </div>
                  <Button 
                    type="button" 
                    variant="ghost" 
                    className="w-full text-sm"
                    onClick={handleResendCode}
                    disabled={isLoading || resendCountdown > 0}
                  >
                    {resendCountdown > 0 
                      ? `Resend Code (${resendCountdown}s)` 
                      : "Resend Code"}
                  </Button>
                </form>
              )}
            </TabsContent>
          </Tabs>
        </CardContent>

        <CardFooter>
          <p className="text-sm text-muted-foreground text-center w-full">
            <Link to="/" className="text-primary hover:underline">
              {t("auth.backToHome")}
            </Link>
          </p>
        </CardFooter>
      </Card>
    </div>
  );
};

export default Auth;
